  ON d.`category_id` = mc.`category_id`
 AND d.`criterion_key` = mc.`criterion_key`
SET mc.`label_de` = d.`label_de`,
    mc.`help_text_de` = d.`help_text_de`;

-- Matrix criteria (200 rows, batch 2).
UPDATE `matrix_criteria` mc
JOIN (
  SELECT 'social-media' AS `category_id`, 'account_visibility_controls' AS `criterion_key`, 'Kontosichtbarkeit' AS `label_de`, 'Kontrollen für öffentliche, private, ungelistete, freigegebene oder suchindexierte Profile.' AS `help_text_de`
  UNION ALL SELECT 'social-media', 'post_audience_controls', 'Zielgruppen für Beiträge', 'Zielgruppenkontrollen für Beiträge, etwa öffentlich, nur Follower, erwähnte Nutzer, lokale Instanz oder Kreise.'
