 AND d.`criterion_key` = mc.`criterion_key`
SET mc.`label_de` = d.`label_de`,
    mc.`help_text_de` = d.`help_text_de`;

-- Matrix criteria (200 rows, batch 8).
UPDATE `matrix_criteria` mc
JOIN (
  SELECT 'video-editing' AS `category_id`, 'multi_track_video' AS `criterion_key`, 'Mehrspur-Video' AS `label_de`, 'Ob der Editor das gleichzeitige Übereinanderlegen mehrerer Videospuren auf der Zeitleiste unterstützt.' AS `help_text_de`
  UNION ALL SELECT 'video-editing', 'multi_track_audio', 'Mehrspur-Audio', 'Ob der Editor das Mischen mehrerer unabhängiger Audiospuren auf der Zeitleiste unterstützt.'
  UNION ALL SELECT 'video-editing', 'trimming_model', 'Schnittmodell', 'Die verfügbaren Präzisionsbearbeitungsmodi zum Schneiden von Clips, wie Ripple-, Roll-, Slip- und Slide-Schnitte.'
  UNION ALL SELECT 'video-editing', 'keyframe_animation', 'Keyframe-Animation', 'Ob Clip-Eigenschaften wie Position, Skalierung, Deckkraft und Effekte mittels Keyframes über die Zeit animiert werden können.'
  UNION ALL SELECT 'video-editing', 'storyboard_mode', 'Storyboard-Modus', 'Ob eine vereinfachte Drag-and-Drop-Storyboard-Ansicht für schnelle Clip-Zusammenstellung und Rohschnitte verfügbar ist.'
  UNION ALL SELECT 'video-editing', 'speed_ramping', 'Geschwindigkeitsrampen', 'Ob das Werkzeug fliessende variable Geschwindigkeitsänderungen innerhalb eines einzelnen Clips mittels Geschwindigkeitskurven unterstützt.'
  UNION ALL SELECT 'video-editing', 'input_video_codecs', 'Eingabe-Videocodecs', 'Die Videocodecs, die zum Bearbeiten importiert und dekodiert werden können, wie H.264, H.265, ProRes oder AV1.'
  UNION ALL SELECT 'video-editing', 'output_video_codecs', 'Ausgabe-Videocodecs', 'Die Videocodecs, die zum Rendern und Exportieren des fertig bearbeiteten Projekts verfügbar sind.'
