-- Matrix criteria (11 rows, batch 9).
UPDATE `matrix_criteria` mc
JOIN (
  SELECT 'photo-management' AS `category_id`, 'encryption_model' AS `criterion_key`, 'Verschlüsselungsmodell' AS `label_de`, 'Die Verschlüsselungsgarantien, die Fotos vor unbefugtem Zugriff bei der Übertragung und Speicherung schützen.' AS `help_text_de`
  UNION ALL SELECT 'photo-management', 'data_export_available', 'Datenexport verfügbar', 'Ob Nutzer ihre vollständige Bibliothek, einschließlich Originale und Metadaten, in Standardformaten exportieren können.'
  UNION ALL SELECT 'photo-management', 'source_code_model', 'Quellcode-Modell', 'Die Offenheit des zugrundeliegenden Quellcodes, von vollständig offen bis hin zu geschlossenen proprietären Versionen.'
  UNION ALL SELECT 'photo-management', 'license_type', 'Lizenztyp', 'Die Softwarelizenz, die die Weitergabe und Änderung des Foto-Werkzeugs regelt.'
  UNION ALL SELECT 'photo-management', 'self_hosting_available', 'Selbsthosting verfügbar', 'Ob die Foto-Plattform auf nutzergesteuerter Infrastruktur installiert und betrieben werden kann.'
  UNION ALL SELECT 'photo-management', 'photo_format_support', 'Foto-Format-Unterstützung', 'Welche Bilddatei-Formate das Werkzeug zum Hochladen akzeptiert und ohne Konvertierung anzeigt.'
