  UNION ALL SELECT 'photo-management', 'pricing_model', 'Preismodell', 'Die Kostenstruktur des Foto-Werkzeugs, von kostenlos über Abonnement bis zum Einmalkauf.'
  UNION ALL SELECT 'photo-management', 'free_tier_available', 'Kostenlose Stufe verfügbar', 'Ob das Foto-Werkzeug eine dauerhaft kostenlose Stufe bietet, die für die tägliche Foto-Verwaltung nutzbar ist.'
  UNION ALL SELECT 'photo-management', 'free_tier_limitations', 'Einschränkungen der kostenlosen Stufe', 'Die Einschränkungen, die für die kostenlose Stufe im Vergleich zu den kostenpflichtigen Versionen des Foto-Werkzeugs gelten.'
  UNION ALL SELECT 'photo-management', 'fit_profiles', 'Eignungsprofile', 'Nutzerprofile und Anwendungsfälle, für die das Foto-Werkzeug aufgrund seines Gesamtfunktionsumfangs am besten geeignet ist.'
) AS d
  ON d.`category_id` = mc.`category_id`
 AND d.`criterion_key` = mc.`criterion_key`
SET mc.`label_de` = d.`label_de`,
    mc.`help_text_de` = d.`help_text_de`;

